import { ref } from 'vue'
import {
  readCookieConsent,
  readStoredThemeMode,
  writeCookieConsent,
  writeThemeCookie,
} from '../utils/themeStorage'

export function useCookieNotice() {
  const visible = ref(readCookieConsent() === null)

  function dismiss() {
    writeCookieConsent('dismissed')
    visible.value = false
  }

  function accept() {
    writeCookieConsent('accepted')
    writeThemeCookie(readStoredThemeMode())
    visible.value = false
  }

  return {
    visible,
    dismiss,
    accept,
  }
}
